</head>
<body>
<?php
require __DIR__ . '/navigation.php';

$pdfMode = !empty($pdfMode);
$esc = static fn($v) => htmlspecialchars((string) $v, ENT_QUOTES, 'UTF-8');
$backUrl = function_exists('route') ? route('general.report') : 'general_report.php';
$printParams = array_filter([
    'declaration_id' => $declarationId ?? ($declaration->declaration_id ?? null),
    'employee_id' => $selectedEmployee->employee_id ?? null,
    'company_id' => $selectedCompany->company_id ?? null,
    'surveillance_id' => $surveillanceId ?? null,
], static fn($value) => $value !== null && $value !== '');
$printUrl = function_exists('route') ? route('pdf.usechh4', $printParams) : 'PDF_USECHH4.php';

$resolvedUser = class_exists('\Illuminate\Support\Facades\Auth') ? \Illuminate\Support\Facades\Auth::user() : null;
$footerFirst = trim((string) (($resolvedUser->first_name ?? $resolvedUser->firstName ?? '') ?: ''));
$footerLast = trim((string) (($resolvedUser->last_name ?? $resolvedUser->lastName ?? '') ?: ''));
$footerName = trim($footerFirst . ' ' . $footerLast);
if ($footerName === '') {
    $footerName = trim((string) (($resolvedUser->name ?? $username ?? 'User') ?: 'User'));
}
$generatedFooter = 'Generated by ' . $footerName . ' at ' . date('D, d M Y h:i A');

$db = class_exists('\Illuminate\Support\Facades\DB') ? \Illuminate\Support\Facades\DB::class : null;
$summaryRow = null;
if ($db && !empty($selectedEmployee->employee_id) && !empty($surveillanceId)) {
    $summaryRow = \Illuminate\Support\Facades\DB::table('summary_report')
        ->where('employee_id', (int) $selectedEmployee->employee_id)
        ->where('surveillance_id', (int) $surveillanceId)
        ->first();
}

$companyId = (int) ($selectedCompany->company_id ?? 0);
$employeeId = (int) ($selectedEmployee->employee_id ?? 0);
$employeeCount = 0;
if ($db && $companyId > 0) {
    $employeeCount = (int) \Illuminate\Support\Facades\DB::table('declaration')
        ->where('company_id', $companyId)
        ->distinct('employee_id')
        ->count('employee_id');
}

$yesNoFromValue = static function ($value): string {
    $value = trim((string) ($value ?? ''));
    if ($value === '') {
        return 'N/A';
    }
    return strcasecmp($value, 'Yes') === 0 ? 'Yes' : 'No';
};
$joinList = static function (array $items, string $fallback = 'N/A'): string {
    $items = array_values(array_filter(array_map(static fn($item) => trim((string) ($item ?? '')), $items), static fn($item) => $item !== ''));
    return $items === [] ? $fallback : implode(', ', $items);
};
$num = static function ($value, string $fallback = '0'): string {
    $value = trim((string) ($value ?? ''));
    return $value === '' ? $fallback : $value;
};
$fmtDate = static function ($value, string $fallback = 'N/A'): string {
    $value = trim((string) ($value ?? ''));
    if ($value === '') {
        return $fallback;
    }
    $time = strtotime($value);
    return $time ? date('d/m/Y', $time) : $value;
};

$workplaceName = trim((string) ($selectedCompany->company_name ?? ''));
$registrationNo = trim((string) (($selectedCompany->mykpp_registration_no ?? $selectedCompany->company_registrationNo ?? '')));
$workplaceAddress = trim((string) ($selectedCompany->company_address ?? ''));
$individualChemical = trim((string) ($chemicalInfo->chemicals ?? ''));
$chraDate = $summaryRow->date_CHRA ?? null;
$chraReportNo = trim((string) ($summaryRow->CHRA_reportNo ?? ''));
$chraReport = trim((string) ($summaryRow->CHRA_report ?? ''));
$joinNatural = static function (array $items, string $fallback = 'N/A'): string {
    $items = array_values(array_filter(array_map(static fn($item) => trim((string) ($item ?? '')), $items), static fn($item) => $item !== ''));
    if ($items === []) {
        return $fallback;
    }
    if (count($items) === 1) {
        return $items[0];
    }
    if (count($items) === 2) {
        return $items[0] . ' and ' . $items[1];
    }
    $last = array_pop($items);
    return implode(', ', $items) . ' and ' . $last;
};

$indicationItems = [];
$chraLower = strtolower($chraReport);
if (str_contains($chraLower, 'reported')) { $indicationItems[] = 'Reported health effects'; }
if (str_contains($chraLower, 'skin')) { $indicationItems[] = 'Skin absorption'; }
if (str_contains($chraLower, 'significant') || str_contains($chraLower, 'pel')) { $indicationItems[] = 'Significant personal exposure (>= 50% PEL)'; }
if (str_contains($chraLower, 'other') && !in_array('Others', $indicationItems, true)) { $indicationItems[] = 'Others'; }
$indicationText = $indicationItems !== [] ? $joinNatural($indicationItems) : ($chraReport !== '' ? $chraReport : 'N/A');
$decisionValue = trim((string) ($summaryRow->decision ?? ''));
if ($decisionValue === '') { $decisionValue = 'N/A'; }

$totalWorkers = $summaryRow->no_workers ?? ($selectedCompany->total_workers ?? $employeeCount);
$workUnit = trim((string) ($summaryRow->work_unit ?? ''));
$exposedWorkers = $summaryRow->no_exposed_workers ?? '';
$examinedWorkers = $summaryRow->no_examined ?? ($employeeId > 0 ? 1 : '');

$healthYes = false;
if (!empty($historyOfHealth)) {
    foreach (get_object_vars($historyOfHealth) as $field => $value) {
        if (in_array($field, ['employee_id', 'surveillance_id', 'others_symptoms'], true)) {
            continue;
        }
        if (trim((string) $value) === 'Yes') {
            $healthYes = true;
            break;
        }
    }
}
$healthText = $summaryRow ? $num($summaryRow->no_workers ?? '', '0') : ($healthYes ? 'Yes' : 'No');
$clinicalText = trim((string) ($msFindings->clinical_findings ?? $clinicalFindings->result_clinical_findings ?? ''));
$targetOrganText = $joinList([
    !empty($targetOrgan->blood_count) ? 'Full blood count' : null,
    !empty($targetOrgan->renal_function) ? 'Renal Profile' : null,
    !empty($targetOrgan->liver_function) ? 'Liver Profile' : null,
    !empty($targetOrgan->chest_xray) ? 'Chest X-ray' : null,
    ($targetOrgan->spirometry_FEV1 ?? null) !== null || ($targetOrgan->spirometry_FVC ?? null) !== null || ($targetOrgan->spirometry_FEV_FVC ?? null) !== null ? 'Spirometry' : null,
], 'N/A');
$beiText = $joinList([
    $biologicalMonitoring->baseline_annual ?? null,
    $biologicalMonitoring->baseline_results ?? null,
    $biologicalMonitoring->biological_exposure ?? null,
], 'N/A');
$workRelatedFlags = [
    trim((string) ($msFindings->CF_work_related ?? '')),
    trim((string) ($msFindings->TO_work_related ?? '')),
    trim((string) ($msFindings->BM_work_related ?? '')),
];
$answeredFlags = array_values(array_filter($workRelatedFlags, static fn($value) => $value !== ''));
$workRelatedText = $answeredFlags === []
    ? 'N/A'
    : (in_array('Yes', $answeredFlags, true) ? 'Yes' : (count(array_filter($answeredFlags, static fn($value) => $value === 'No')) === count($answeredFlags) ? 'No' : 'N/A'));
$conclusionText = trim((string) ($msFindings->conclusion_fitness ?? ''));
$mrpCount = $summaryRow->no_MRP ?? ($conclusionText === 'Not Fit' ? 1 : 0);
$laboratory = trim((string) ($summaryRow->laboratory ?? ''));
$recommendationText = trim((string) ($summaryRow->recommendation ?? ''));
$decisionContinue = trim((string) ($summaryRow->decision ?? '')) === 'Continue MS';
$decisionStop = trim((string) ($summaryRow->decision ?? '')) === 'Stop MS';
$decisionJustification = trim((string) ($summaryRow->justification_decision ?? ''));
$dateImplementation = $summaryRow->date_implementation ?? null;
$doctorName = trim((string) ((($doctor->doctor_firstName ?? '') . ' ' . ($doctor->doctor_lastName ?? ''))));
$doctorReg = trim((string) (($doctor->doctor_registrationNo ?? $doctor->OHD_registrationNo ?? '')));
$doctorPractice = trim((string) ($doctor->doctor_practiceAddress ?? ''));
$doctorTel = trim((string) ($doctor->doctor_telephone ?? ''));
$doctorHp = trim((string) ($doctor->doctor_hpNo ?? ''));
$doctorFax = trim((string) ($doctor->doctor_faxNo ?? ''));
$doctorEmail = trim((string) ($doctor->doctor_email ?? ''));
$currentDate = $chemicalInfo->examination_date ?? null;

medis_render_navigation_start([
    'clinicName' => $clinicName ?? 'Medis SHAMS',
    'clinicLogoUrl' => $clinicLogoUrl ?? null,
    'username' => $username ?? 'User',
    'active' => '',
    'pdfMode' => $pdfMode,
]);
?>
<style>
