{border:1px solid #dfe5ea;padding:10px 12px;vertical-align:top;font-size:13px;line-height:1.4}.exam-table thead th{background:#eef7f0;font-size:.84rem;font-weight:700;color:#1f2937;text-align:center}.exam-table tbody th,.exam-table tbody td.label-cell{background:#f8fbf8;font-weight:600;text-align:left;color:#14321f}.exam-table.clean-report tbody td{background:#fff;color:#334155}.exam-table.clean-report td.center{text-align:center}.foot-note{padding:10px 12px;border:1px solid #dfe5ea;border-top:0;border-radius:0 0 18px 18px;font-size:13px;font-weight:600;color:#0f172a;background:#fff}.section-stack{display:grid;gap:8px;margin-top:14px}.sign-row{display:grid;grid-template-columns:1fr 1fr;gap:32px;margin-top:24px}.sign-field{display:grid;gap:8px}.pdf-footer{margin-top:14px;padding-top:8px;border-top:1px solid #e5e7eb;text-align:right;font-size:11px;color:#64748b}.pdf-mode .sheet{padding:0;border:0;border-radius:0;box-shadow:none}.pdf-mode .app-page{padding:0!important;background:#fff}.pdf-mode .report-page{padding:0;background:#fff}.pdf-mode .report-actions{display:none!important}.pdf-mode .pdf-footer{position:fixed;left:0;right:0;bottom:0;margin:0;padding-top:6px;background:#fff;border-top:1px solid #e5e7eb}@media print{body{background:#fff}.app-topbar,.app-sidebar,.report-actions{display:none!important}.app-shell{display:block}.app-main,.app-page,.app-card{display:block;height:auto;overflow:visible;padding:0!important;border:0!important;background:#fff!important}.sheet{padding:0;border:0;box-shadow:none}.report-page{max-width:none}}@media(max-width:980px){.sign-row{grid-template-columns:1fr}.report-page{overflow:auto;width:100%}.meta-row,.summary-line{display:grid;gap:4px}.meta-label,.summary-label{min-width:0}}
</style>
