        <div class="meta-row"><span class="meta-label">Indication for medical surveillance based on CHRA report: </span><span class="meta-value"><?php echo $esc($indicationText); ?></span></div>

        <div class="table-wrap"><table class="exam-table clean-report">
            <thead>
                <tr><th colspan="5">MEDICAL SURVEILLANCE RESULTS</th></tr>
                <tr>
                    <th rowspan="2" style="width:30%;">&nbsp;</th>
                    <th rowspan="2" style="width:14%;">No. of workers with normal findings</th>
                    <th colspan="2" style="width:32%;">No. of workers with abnormal findings</th>
                    <th rowspan="2" style="width:24%;">No. of workers recommended for medical removal protection</th>
                </tr>
                <tr>
                    <th>Occupational</th>
                    <th>Non-occupational</th>
                </tr>
            </thead>
            <tbody>
                <tr>
                    <td class="label-cell">History of health effects due to chemical exposure (*H)</td>
                    <td><?php echo $esc($healthText); ?></td>
                    <td><?php echo $esc($conclusionText === 'Not Fit' ? '1' : '0'); ?></td>
                    <td>Not applicable</td>
                    <td>Not applicable</td>
                </tr>
                <tr>
                    <td class="label-cell">Clinical findings (*I)</td>
                    <td><?php echo $esc($clinicalText !== '' ? $clinicalText : 'N/A'); ?></td>
                    <td><?php echo $esc($conclusionText === 'Not Fit' && $clinicalText !== '' ? '1' : '0'); ?></td>
                    <td><?php echo $esc($conclusionText !== 'Not Fit' && $clinicalText !== '' ? '1' : '0'); ?></td>
                    <td><?php echo $esc($conclusionText === 'Not Fit' ? '1' : '0'); ?></td>
                </tr>
                <tr>
                    <td class="label-cell">Target organ function test(s) (*J). Please specify:</td>
                    <td><?php echo $esc($targetOrganText); ?></td>
                    <td><?php echo $esc($conclusionText === 'Not Fit' && $targetOrganText !== 'N/A' ? '1' : '0'); ?></td>
                    <td><?php echo $esc($conclusionText !== 'Not Fit' && $targetOrganText !== 'N/A' ? '1' : '0'); ?></td>
                    <td><?php echo $esc($conclusionText === 'Not Fit' ? '1' : '0'); ?></td>
                </tr>
                <tr>
                    <td class="label-cell">BEI determinant (*K) (BM/BEM). Please specify determinant:</td>
                    <td><?php echo $esc($beiText); ?></td>
                    <td><?php echo $esc($conclusionText === 'Not Fit' && $beiText !== 'N/A' ? '1' : '0'); ?></td>
                    <td><?php echo $esc($conclusionText !== 'Not Fit' && $beiText !== 'N/A' ? '1' : '0'); ?></td>
                    <td><?php echo $esc($conclusionText === 'Not Fit' ? '1' : '0'); ?></td>
                </tr>
            </tbody>
        </table><div class="foot-note">Continue in separate sheet if required. Please include details of abnormal examination/test results in USECHH 5ii form and Medical Removal Protection in USECHH 5i form.</div></div>

        <div class="section-stack">
