            <div class="meta-row"><span class="meta-label">Name of Laboratory: </span><span class="meta-value"><?php echo $esc($laboratory !== '' ? $laboratory : 'N/A'); ?></span></div>
            <div class="meta-row"><span class="meta-label">Recommendation: </span><span class="meta-value"><?php echo $esc($recommendationText !== '' ? $recommendationText : 'N/A'); ?></span></div>
